import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { LineItem } from '../../data/models';

@Component({
  selector: 'app-validation',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './validation.component.html',
  styleUrl: './validation.component.css',
})
export class ValidationComponent {
  // Local active-toggle state keyed by rule id (mockup, does not mutate the seed).
  readonly activeState = signal<Record<string, boolean>>({});

  isActive(id: string, seeded: boolean): boolean {
    const state = this.activeState();
    return id in state ? state[id] : seeded;
  }

  toggleActive(id: string, seeded: boolean): void {
    const current = this.isActive(id, seeded);
    this.activeState.update((s) => ({ ...s, [id]: !current }));
  }

  activeRulesCount = computed(() =>
    this.seed.validationRules().filter((r) => this.isActive(r.id, r.active)).length,
  );

  totalTriggers = computed(() =>
    this.seed.validationRules().reduce((sum, r) => sum + r.triggers, 0),
  );

  recentResults = computed(() =>
    this.seed.lineItems()
      .filter((l) => l.validationStatus !== 'ok')
      .map((l) => ({
        item: l,
        quote: this.seed.quoteById(l.quoteId),
      })),
  );

  openIssues = computed(() => this.recentResults().length);

  severityBadge(severity: string): string {
    return severity === 'error' ? 'badge-danger' : 'badge-warning';
  }

  resultBadge(status: LineItem['validationStatus']): string {
    switch (status) {
      case 'error': return 'badge-danger';
      case 'warning': return 'badge-warning';
      default: return 'badge-success';
    }
  }

  constructor(public seed: SeedService) {}
}
